example.code:
/* Dyslexia-friendly typography */
body {
  font-family: Arial, Verdana, sans-serif; /* clean sans-serif */
  font-size: 16px;
  line-height: 1.5;
  letter-spacing: 0.12em;
  word-spacing: 0.16em;
  text-align: left; /* never justify */
}

p {
  max-width: 70ch; /* optimal line length */
  margin-bottom: 2em;
}
